SELECT threshold_value, algorithm_used
FROM filter_settings
WHERE algorithm_used = 'BWA';

SELECT DISTINCT r.researcher_name
FROM researchers r
JOIN analyses a ON r.researcher_id = a.researcher_id;

SELECT researcher_name, affiliation
FROM researchers
WHERE researcher_id IN (SELECT user_id FROM access_logs);

SELECT datasets.dataset_name, analyses.analysis_type
FROM analyses
JOIN datasets ON analyses.dataset_id = datasets.dataset_id;

SELECT dataset_name, version 
FROM datasets 
WHERE dataset_id > 5;
